Jawaban Benar:
GRANT 'privilege list'
ON 'relation name or view name'
TO 'user/role list';

Jawaban Salah 1:
GRANT 'privilege list'
   ON 'user/role list'
   TO 'relation name or view name';

Jawaban Salah 3:
GRANT 'privilege list'
   ON 'relation name or view name'
   ON 'user/role list';

Jawaban Salah 4:
GRANT 'privilege list'
TO 'relation name or view name'
TO 'user/role list';

Jawaban Benar:
CREATE ROLE instructor;
GRANT DELETE ON takes
TO instructor;

Jawaban Salah 2:
CREATE ROLE instructor;
GRANT SELECT ON takes
TO instructor;

Jawaban Salah 3:
CREATE ROLE instructor;
GRANT SELECT ON takes
ON instructor;

Jawaban Salah 4:
CREATE ROLE instructor;
GRANT INSERT ON takes
TO instructor;

Pertanyaan:
Berdasarkan perintah berikut:
TRANSACTION. . . . .
Commit;
ROLLBACK;
Apa yang dilakukan oleh perintah ROLLBACK?

Jawaban Benar:
BEGIN TRANSACTION;
GO
DELETE FROM HumanResources.JobCandidate
    WHERE JobCandidateID = 13;
GO
COMMIT TRANSACTION;

Jawaban Salah 1:
BEGIN TRANSACTION;
GO
DELETE FROM HumanResources.JobCandidate
    WHERE JobCandidateID = 13;
GO
ROLLBACK TRANSACTION;

Jawaban Salah 2:
BEGIN TRANSACTION;
GO
DELETE FROM HumanResources.JobCandidate
    WHERE JobCandidateID = 13;
GO
END;

Jawaban Salah 3:
BEGIN TRANSACTION;
GO
DELETE FROM HumanResources.JobCandidate;
GO
COMMIT TRANSACTION;

Jawaban Salah 4:
BEGIN TRANSACTION;
GO
DELETE FROM HumanResources.JobCandidate;
GO
END;
